(39, 1, '2026-05-01 12:23:19', '2026-05-01 12:23:19', '[ux_slider class=\"cs-slider\"]\n\n[ux_banner height=\"100%\" height__sm=\"100%\" bg=\"15\" bg_size=\"original\" bg_overlay=\"rgba(45, 45, 45, 0.337)\" class=\"cs-hero-overlay\"]\n\n[text_box width=\"75\" width__sm=\"60\" position_x=\"15\" position_y=\"50\" class=\"cs-hero-content\"]\n\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"rgb(255, 255, 255)\"]\n\n<h2 class=\"cs-mb-0\"><strong>VIỆT NAM</strong></h2>\n[/ux_text]\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"#c49d59\"]\n\n<h2><strong>VẺ ĐẸP BẤT TẬN</strong></h2>\n[/ux_text]\n[ux_text text_align=\"left\" text_color=\"rgb(255,255,255)\" class=\"cs-hero-content\"]\n\n<p>Hành trình khám phá vẻ đẹp lịch sử, văn hóa, và cảnh quan thiên nhiên tráng lệ trải dài khắp 3 miền.</p>\n[/ux_text]\n[row v_align=\"equal\"]\n\n[col span=\"10\" span__sm=\"12\" align=\"left\" class=\"cs-button-banner\"]\n\n[ux_html]\n\n<a href=\"#\" class=\"cs-btn cs-btn-solid\"><i class=\"fas fa-compass\"></i> KHÁM PHÁ NGAY</a>\n[/ux_html]\n[button text=\"Xem  bảng đồ\" style=\"outline\" radius=\"99\" class=\"cs-btn cs-btn-outline\"]\n\n\n[/col]\n\n[/row]\n\n[/text_box]\n\n[/ux_banner]\n[ux_banner height=\"100%\" bg=\"11\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.5)\" class=\"cs-hero-overlay\"]\n\n[text_box width=\"75\" width__sm=\"60\" position_x=\"15\" position_y=\"50\" class=\"cs-hero-content\"]\n\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"rgb(255, 255, 255)\"]\n\n<h2 class=\"cs-mb-0\"><strong>VIỆT NAM</strong></h2>\n[/ux_text]\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"#c49d59\"]\n\n<h2><strong>KÌ QUAN THẾ GIỚI</strong></h2>\n[/ux_text]\n[ux_text text_align=\"left\" text_color=\"rgb(255,255,255)\" class=\"cs-hero-content\"]\n\n<p>Chiêm ngưỡng những dãy núi đá vôi hùng vĩ và hệ thống hang động bí ẩn của di sản Tràng An.</p>\n[/ux_text]\n[row v_align=\"equal\"]\n\n[col span=\"10\" span__sm=\"12\" align=\"left\" class=\"cs-button-banner\"]\n\n[ux_html]\n\n<a href=\"#\" class=\"cs-btn cs-btn-solid\"><i class=\"fas fa-compass\"></i> KHÁM PHÁ NGAY</a>\n[/ux_html]\n[button text=\"Xem  bảng đồ\" style=\"outline\" radius=\"99\" class=\"cs-btn cs-btn-outline\"]\n\n\n[/col]\n\n[/row]\n\n[/text_box]\n\n[/ux_banner]\n[ux_banner height=\"100%\" bg=\"9\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.5)\" class=\"cs-hero-overlay\"]\n\n[text_box width=\"75\" width__sm=\"60\" position_x=\"15\" position_y=\"50\" class=\"cs-hero-content\"]\n\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"rgb(255, 255, 255)\"]\n\n<h2 class=\"cs-mb-0\"><strong>VIỆT NAM</strong></h2>\n[/ux_text]\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"#c49d59\"]\n\n<h2><strong>DI SẢN VĂN HÓA</strong></h2>\n[/ux_text]\n[ux_text text_align=\"left\" text_color=\"rgb(255,255,255)\" class=\"cs-hero-content\"]\n\n<p>Dạo bước trên những con phố cổ ngập tràn ánh đèn lồng rực rỡ và những mái ngói rêu phong.</p>\n[/ux_text]\n[row v_align=\"equal\"]\n\n[col span=\"10\" span__sm=\"12\" align=\"left\" class=\"cs-button-banner\"]\n\n[ux_html]\n\n<a href=\"#\" class=\"cs-btn cs-btn-solid\"><i class=\"fas fa-compass\"></i> KHÁM PHÁ NGAY</a>\n[/ux_html]\n[button text=\"Xem  bảng đồ\" style=\"outline\" radius=\"99\" class=\"cs-btn cs-btn-outline\"]\n\n\n[/col]\n\n[/row]\n\n[/text_box]\n\n[/ux_banner]\n[ux_banner height=\"100%\" bg=\"16\" bg_size=\"original\" bg_overlay=\"rgba(0, 0, 0, 0.5)\" class=\"cs-hero-overlay\"]\n\n[text_box width=\"75\" width__sm=\"60\" position_x=\"15\" position_y=\"50\" class=\"cs-hero-content\"]\n\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"rgb(255, 255, 255)\"]\n\n<h2 class=\"cs-mb-0\"><strong>VIỆT NAM</strong></h2>\n[/ux_text]\n[ux_text font_size=\"3\" text_align=\"left\" text_color=\"#c49d59\"]\n\n<h2><strong>BỨC TRANH THIÊN NHIÊN</strong></h2>\n[/ux_text]\n[ux_text text_align=\"left\" text_color=\"rgb(255,255,255)\" class=\"cs-hero-content\"]\n\n<p>Chinh phục đỉnh cao và ngắm trọn toàn cảnh non nước hữu tình từ những điểm nhìn ngoạn mục nhất.</p>\n[/ux_text]\n[row v_align=\"equal\"]\n\n[col span=\"10\" span__sm=\"12\" align=\"left\" class=\"cs-button-banner\"]\n\n[ux_html]\n\n<a href=\"#\" class=\"cs-btn cs-btn-solid\"><i class=\"fas fa-compass\"></i> KHÁM PHÁ NGAY</a>\n[/ux_html]\n[button text=\"Xem  bảng đồ\" style=\"outline\" radius=\"99\" class=\"cs-btn cs-btn-outline\"]\n\n\n[/col]\n\n[/row]\n\n[/text_box]\n\n[/ux_banner]\n\n[/ux_slider]', 'Banner-Home', '', 'publish', 'closed', 'closed', '', 'banner-home', '', '', '2026-05-10 09:41:22', '2026-05-10 09:41:22', '', 0, 'http://travelwp.test/?post_type=blocks&#038;p=39', 0, 'blocks', '', 0),
