n nước hữu tình từ những điểm nhìn ngoạn mục nhất.</p>\n\n[/ux_text]\n[row v_align=\"equal\"]\n\n[col span=\"10\" span__sm=\"12\" align=\"left\" class=\"cs-button-banner\"]\n\n[ux_html]\n\n<a href=\"#\" class=\"cs-btn cs-btn-solid\"><i class=\"fas fa-compass\"></i> KHÁM PHÁ NGAY</a>\n[/ux_html]\n[button text=\"Xem  bảng đồ\" style=\"outline\" radius=\"99\" class=\"cs-btn cs-btn-outline\"]\n\n\n[/col]\n\n[/row]\n\n[/text_box]\n\n[/ux_banner]\n\n[/ux_slider]', 'Banner-Home', '', 'inherit', 'closed', 'closed', '', '39-revision-v1', '', '', '2026-05-02 08:11:09', '2026-05-02 08:11:09', '', 39, 'http://travelwp.test/?p=139', 0, 'revision', '', 0);
