(155, 1, '2026-05-02 13:18:41', '2026-05-02 13:18:41', 'a:12:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:4:\"text\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:17:\"allow_in_bindings\";i:0;s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";}', 'Ẩm thực', 'am_thuc', 'publish', 'closed', 'closed', '', 'field_69f5f9a5495ef', '', '', '2026-05-02 14:31:14', '2026-05-02 14:31:14', '', 151, 'http://travelwp.test/?post_type=acf-field&#038;p=155', 3, 'acf-field', '', 0),
(156, 1, '2026-05-02 13:31:39', '2026-05-02 13:31:39', '<span class=\"cs-drop-cap\">N</span>inh Bình không chỉ là một bức tranh thủy mặc tuyệt đẹp, mà còn là một cuốn sử thi hào hùng được tạc bằng đá núi. Trong chuyến đi khám phá lần này, chúng tôi đưa bạn quay ngược thời gian, trở về với những câu chuyện chưa từng được kể về Cố đô Hoa Lư.\r\n\r\nHành trình bắt đầu từ dòng sông Ngô Đồng phẳng lặng, nơi những người lái đò địa phương vẫn ngày ngày kể lại sự tích về vua Đinh Tiên Hoàng bằng chất giọng mộc mạc mang đậm hơi thở của vùng đất bãi bồi.\r\n\r\n<img class=\"size-medium wp-image-166 aligncenter\" src=\"http://travelwp.test/wp-content/uploads/2026/05/boat-1-300x300.jpg\" alt=\"\" width=\"100%\" />\r\n<div>\r\n\r\n[cs_quote]\"Mỗi tảng đá ở đây đều có linh hồn. Cứ đến mùa nước lên, dường như chúng lại cất tiếng hát vọng về từ quá khứ ngàn năm.\"[/cs_quote]\r\n\r\n</div>\r\nXuyên suốt hành trình, bạn sẽ không chỉ tập trung vào cảnh sắc hùng vĩ của Tràng An hay Tam Cốc, mà còn đi sâu vào đời sống tĩnh lặng của những người thợ chạm khắc đá thủ công ở Ninh Vân. Bàn tay họ thô ráp, nứt nẻ, nhưng từng nhát búa vung lên đều là sự kế thừa tinh hoa từ bao thế hệ trước.\r\n\r\n[cs_video url=\"https://www.youtube.com/watch?v=vDBnh2WrQwA&amp;list=RDvDBnh2WrQwA&amp;start_radio=1\"]', 'Ninh Bình Ký Ức Sống', 'Tiếng vọng từ ngàn năm cố đô Hoa Lư.', 'publish', 'closed', 'closed', '', 'hanh-trinh-kham-pha-co-do-hoa-lu', '', '', '2026-05-10 05:52:41', '2026-05-10 05:52:41', '', 0, 'http://travelwp.test/?p=156', 0, 'post', '', 0),
