(180, 1, '2026-05-02 15:17:09', '2026-05-02 15:17:09', '[section]\n\n[row v_align=\"middle\"]\n\n[col span=\"6\" span__sm=\"12\"]\n\n<h2>Bắt đầu Hành trình của bạn</h2>\n<p>Hãy để lại thông tin, các chuyên viên tư vấn của chúng tôi sẽ liên hệ với bạn trong thời gian sớm nhất để thiết kế một chuyến đi đáng nhớ.</p>\n\n[ux_html]\n\n<div style=\"display: flex; gap: 20px; margin-top: 20px;\">\n                    <i class=\"fas fa-headset\" style=\"font-size: 2.5rem; color: var(--gold);\"></i>\n                    <div>\n                        <div style=\"font-size: 0.85rem; color: var(--text-muted); text-transform: uppercase;\">Hotline hỗ trợ 24/7</div>\n                        <div style=\"font-size: 1.2rem; font-weight: 600; color: var(--text-main);\">0823 456 789</div>\n                    </div>\n                </div>\n[/ux_html]\n\n[/col]\n[col span=\"6\" span__sm=\"12\"]\n\n[contact-form-7 id=\"8\"]\n\n\n[/col]\n\n[/row]\n\n[/section]', 'Footer', '', 'inherit', 'closed', 'closed', '', '20-revision-v1', '', '', '2026-05-02 15:17:09', '2026-05-02 15:17:09', '', 20, 'http://travelwp.test/?p=180', 0, 'revision', '', 0),
